import { Container, Row, Col } from 'react-bootstrap';

function Footer() {
  return (
    <footer className="bg-dark text-light py-4 mt-auto">
      <Container>
        <Row>
          <Col md={4}>
            <h6>eTiskárna</h6>
            {/* Krátký popis firmy */}
          </Col>
          <Col md={4}>
            <h6>Navigace</h6>
            {/* Odkazy */}
          </Col>
          <Col md={4}>
            <h6>Kontakt</h6>
            {/* Kontaktní údaje */}
          </Col>
        </Row>
        <hr className="border-secondary" />
        <p className="text-center text-secondary mb-0 small">
          &copy; {new Date().getFullYear()} eTiskárna. Všechna práva vyhrazena.
        </p>
      </Container>
    </footer>
  );
}

export default Footer;
